        (needle_len == haystack_len || haystack[needle_len] == ',')) {
        return haystack;
    }

    // Search for commas
    while((s = (unsigned char *) memchr((char *) s, ',', left)) != NULL) {
        left = end_haystack - s;
        if((left >= 1) && (left <= haystack_len) && (left > needle_len)) {
            s++;  // Advance past comma
        }
        else {
            return NULL;
        }

        // Check if needle matches at this position
        if((strncmp((char *) s, (char *) needle, needle_len) == 0) &&
            (((s - haystack) + needle_len) == haystack_len
             || s[needle_len] == ',')) {
            return s;
        }
    }

    return NULL;
}
```

The vulnerability is in the `while` loop - when `memchr` searches for a comma, if the needle isn't found and there's no comma near the end, the function can still proceed to read `s[needle_len]` which could be out of bounds.

The critical issue is at line 3358-3360:
